// AppleSignIn.js
import AppleSigninButton from 'react-apple-signin-auth';

function AppleSignIn() {
  const handleSuccess = (data) => {
    const { authorization, user } = data;
    // Send data to your backend for verification
    console.log('Apple Sign In Success:', data);
  };

  const authOptions = {
    clientId: 'your.service.id', // Your Service ID
    scope: 'email name',
    redirectURI: 'https://your-domain.com',
    nonce: 'nonce',
    usePopup: true, // Recommended for single-page apps
  };

  return (
    <AppleSigninButton
      authOptions={authOptions}
      uiType="dark"
      className="apple-auth-btn"
      onSuccess={handleSuccess}
      onError={(error) => console.error(error)}
    />
  );
}`}),E.jsx("h4",{children:"Understanding the Apple Response"}),E.jsx("p",{children:"Apple's response structure varies between first-time and returning users:"}),E.jsx("pre",{style:{background:"#2d2d2d",color:"#f8f8f2",padding:"1rem",borderRadius:"4px",overflow:"auto"},children:`// First-time user response
